<script>
(function(){
  var io=new IntersectionObserver(function(entries){
    entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}});
  },{threshold:0.1});
  document.querySelectorAll('.reveal').forEach(function(el){io.observe(el)});

  var GTM='GTM-XXXXXXX',PIX='XXXXXXXXXXXXXXXXXX',KEY='interiorar_cookies_v1';
  var ov=document.getElementById('cookie-overlay');
  var pm=document.getElementById('cp-main'),pc=document.getElementById('cp-config');
  var am=document.getElementById('ca-main'),ac=document.getElementById('ca-cfg');
  function prefs(){try{return JSON.parse(localStorage.getItem(KEY))||null}catch(e){return null}}
  function save(a,m){localStorage.setItem(KEY,JSON.stringify({analytics:a,marketing:m,date:new Date().toISOString()}))}
  function close(){ov.classList.remove('on');document.body.classList.remove('noscroll')}
  function open(){ov.classList.add('on');document.body.classList.add('noscroll')}
  function loadGTM(){if(window._gl)return;window._gl=1;(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({'gtm.start':new Date().getTime(),event:'gtm.js'});var f=d.getElementsByTagName(s)[0],j=d.createElement(s),dl=l!='dataLayer'?'&l='+l:'';j.async=true;j.src='https://www.googletagmanager.com/gtm.js?id='+i+dl;f.parentNode.insertBefore(j,f)})(window,document,'script','dataLayer',GTM)}
  function loadPix(){if(window._px)return;window._px=1;!function(f,b,e,v,n,t,s){if(f.fbq)return;n=f.fbq=function(){n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}(window,document,'script','https://connect.facebook.net/en_US/fbevents.js');fbq('init',PIX);fbq('track','PageView')}
  function apply(p){if(p.analytics)loadGTM();if(p.marketing)loadPix();close()}
  document.getElementById('c-acc').onclick=function(){save(true,true);apply({analytics:true,marketing:true})};
  document.getElementById('c-rej').onclick=function(){save(false,false);close()};
  document.getElementById('c-cfg').onclick=function(){pm.style.display='none';pc.style.display='block';am.style.display='none';ac.style.display='flex'};
  document.getElementById('c-bk').onclick=function(){pm.style.display='block';pc.style.display='none';am.style.display='flex';ac.style.display='none'};
  document.getElementById('c-sv').onclick=function(){var a=document.getElementById('t-a').checked,m=document.getElementById('t-m').checked;save(a,m);apply({analytics:a,marketing:m})};
  var p=prefs();if(p){apply(p)}else{open()}
})();
</script>
